export const INSTALL_EVENT_NSIS_CANCEL = 'nsis_install_cancel'

// ==================== 平台标识 ====================

/**
 * 获取上报用的平台标识（event_params 字段）
 *
 * - Windows → Qclaw_Win
 * - macOS ARM → Qclaw_MAC_ARM
 * - macOS Intel → Qclaw_MAC_INTEL
 */
export function getReportPlatformId(): string {
  if (process.platform === 'win32') {
    return 'Qclaw_Win'
  }
  if (process.platform === 'darwin') {
    return process.arch === 'arm64' ? 'Qclaw_MAC_ARM' : 'Qclaw_MAC_INTEL'
  }
  return `Qclaw_${process.platform}_${process.arch}`
}

